sql:
SELECT races.race_name, race_courses.course_name
FROM races
INNER JOIN race_courses ON races.course_id = race_courses.course_id;

SELECT races.race_name, race_types.type_name
FROM races
INNER JOIN race_types ON races.race_type_id = race_types.race_type_id;

SELECT race_track_id, track_name, location, capacity, elevation
FROM race_tracks
WHERE location = 'Baltimore, MD';

SELECT track_name 
FROM race_tracks
WHERE capacity > (SELECT AVG(capacity) FROM race_tracks);

SELECT course_id, race_track_id
FROM race_courses
WHERE course_set_status_id = 0 AND ground_type = 1;

SELECT AVG(elevation) 
FROM race_tracks
WHERE capacity > 8000 AND elevation <= 100;

SELECT track_name 
FROM race_tracks 
WHERE race_track_id = 1;

external_knowledge:
- 'dry' conditions refer to races held in good weather; 
- 'typical duration' in the question refers to an average finish time, calculated by averaging the finish times with a random range adjustment; 
- 'turf' is indicated by the ground type being '1'.

sql:
SELECT race_name, actual_finish_time
FROM races
WHERE actual_finish_time = (SELECT MAX(actual_finish_time) FROM races);

SELECT ground_type_id, type_name, description, maintainance_frequency, drainage_capacity
FROM ground_types
WHERE ground_type_id = 1;
